import{_ as a,o as t,c as o,a2 as i}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"CZeroX App","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/app.md","filePath":"en/guide/app.md","lastUpdated":1783349713000}'),r={name:"en/guide/app.md"};function n(s,e,l,d,c,h){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="czerox-app" tabindex="-1">CZeroX App <a class="header-anchor" href="#czerox-app" aria-label="Permalink to &quot;CZeroX App&quot;">​</a></h1><p><strong>CZeroX</strong> is CZero&#39;s native companion app, built with Jetpack Compose, that reads and writes the module&#39;s <code>config.json</code> directly. It is the module&#39;s only graphical configuration frontend — no WebUI.</p><h2 id="download" tabindex="-1">Download <a class="header-anchor" href="#download" aria-label="Permalink to &quot;Download&quot;">​</a></h2><p>Download the latest CZeroX APK from the <a href="https://github.com/Xocio/CZero/releases" target="_blank" rel="noreferrer">Releases</a> page and install it.</p><h2 id="key-capabilities" tabindex="-1">Key capabilities <a class="header-anchor" href="#key-capabilities" aria-label="Permalink to &quot;Key capabilities&quot;">​</a></h2><h3 id="home-dashboard" tabindex="-1">Home dashboard <a class="header-anchor" href="#home-dashboard" aria-label="Permalink to &quot;Home dashboard&quot;">​</a></h3><ul><li><strong>Daemon status</strong> — PID and memory usage; restart it in one tap if it isn&#39;t running.</li><li><strong>Cleaning stats</strong> — today&#39;s and total figures (from <code>basis.prop</code>).</li><li><strong>F2FS status card</strong> — live dirty / free / used / total segment counts.</li></ul><h3 id="one-tap-actions" tabindex="-1">One-tap actions <a class="header-anchor" href="#one-tap-actions" aria-label="Permalink to &quot;One-tap actions&quot;">​</a></h3><ul><li>Clean now (run all cleaning jobs)</li><li>Per-app cleaning</li><li>Background suppression</li><li>F2FS GC (primary / backup plan)</li><li>Empty-folder cleanup</li></ul><p>Progress and results are surfaced via notifications.</p><h3 id="settings-editor" tabindex="-1">Settings editor <a class="header-anchor" href="#settings-editor" aria-label="Permalink to &quot;Settings editor&quot;">​</a></h3><p>Covers every field in <code>config.json</code>: feature switches, schedule intervals and times, GC thresholds, the temporal barrier, and more. Saved changes are hot-reloaded by the daemon — no reboot.</p><h3 id="rule-editor" tabindex="-1">Rule editor <a class="header-anchor" href="#rule-editor" aria-label="Permalink to &quot;Rule editor&quot;">​</a></h3><p>Manage the black/white lists and the custom path list (<code>clean_paths.prop</code>) to widen or narrow the cleaning scope.</p><h3 id="recycle-bin" tabindex="-1">Recycle bin <a class="header-anchor" href="#recycle-bin" aria-label="Permalink to &quot;Recycle bin&quot;">​</a></h3><p>View the recycle sessions produced by cleaning (file count, size, expiry) and restore accidentally deleted files back to their original locations with one tap. The data comes from the <code>list</code> / <code>restore</code> subcommands of <code>list/customize</code>; cleaned files are kept for 7 days by default. See <a href="/en/guide/features#recycle-bin-restore">Features · Recycle bin &amp; restore</a>.</p><h2 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">​</a></h2><p>CZeroX supports <strong>English</strong> and <strong>简体中文</strong>, following the system or switchable in-app.</p><h2 id="relationship-to-the-module" tabindex="-1">Relationship to the module <a class="header-anchor" href="#relationship-to-the-module" aria-label="Permalink to &quot;Relationship to the module&quot;">​</a></h2><p>CZeroX does no cleaning itself — it only <strong>reads/writes <code>config.json</code> and displays status</strong>; the actual scheduling and cleaning are done by the C++ daemon inside the module. So even without CZeroX the module runs fine on its default config — the app simply makes configuring and monitoring intuitive.</p>',20)])])}const g=a(r,[["render",n]]);export{u as __pageData,g as default};
